@using sv_64ccde3dffc14851acfa4f08f4b64808.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center gap-2">
    <label class="text-nowrap mb-0 fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_64ccde3dffc14851acfa4f08f4b64808.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount.HasValue && _lowStockCount.Value > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@_lowStockCount</span>
}

@code {
    private int? _lowStockCount;
    private CancellationTokenSource? _cts;
    private Timer? _timer;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshCountAsync();
        _timer = new Timer(async _ => await RefreshCountAsync(), null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — refresh immediately.
        await RefreshCountAsync();
    }

    private async Task RefreshCountAsync()
    {
        try
        {
            var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
            _lowStockCount = count;
            await InvokeAsync(StateHasChanged);
        }
        catch (ObjectDisposedException)
        {
            // Component disposed during async work — safe to ignore.
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _timer?.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

