@page "/dashboard"
@rendermode InteractiveServer
@using sv_64ccde3dffc14851acfa4f08f4b64808.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Managing: <strong>@WarehouseState.CurrentWarehouse.Name</strong> (@WarehouseState.CurrentWarehouseId)</p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                @if (_lowStockCount is null)
                {
                    <p class="display-4 text-muted">—</p>
                }
                else if (_lowStockCount > 0)
                {
                    <p class="display-4 text-danger">@_lowStockCount</p>
                    <p class="text-danger">Items below minimum level</p>
                }
                else
                {
                    <p class="display-4 text-success">0</p>
                    <p class="text-success">All stock levels healthy</p>
                }
            </div>
            <div class="card-footer text-muted text-center">
                Refreshes every 10 seconds
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouse.Name</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6 text-success">Active</p>
                <p class="text-muted">Last check: @_lastCheck?.ToString("HH:mm:ss")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private DateTime? _lastCheck;
    private Timer? _pollingTimer;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await PollAsync();
        _pollingTimer = new Timer(async _ => await PollAsync(), null,
            TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async void OnWarehouseChanged()
    {
        // User picked a new warehouse — poll immediately.
        await PollAsync();
    }

    private async Task PollAsync()
    {
        try
        {
            _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
            _lastCheck = DateTime.Now;
            await InvokeAsync(StateHasChanged);
        }
        catch (ObjectDisposedException)
        {
            // Component was disposed during the async callback — ignore.
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _pollingTimer?.Dispose();
    }
}

